import { Injectable } from '@angular/core';
import { NgbDateAdapter, NgbDateStruct } from '@ng-bootstrap/ng-bootstrap';
import dayjs, { Dayjs } from 'dayjs';
import utc from 'dayjs/plugin/utc';
dayjs.extend(utc);

@Injectable({
  providedIn: 'root',
})
export class DateAdapter extends NgbDateAdapter<Dayjs> {
  public fromModel(date: Dayjs | null): NgbDateStruct | null {
    if (!date?.isValid()) {
      return null;
    }

    const utcDate = date.utc();

    return {
      year: utcDate.year(),
      month: utcDate.month() + 1,
      day: utcDate.date(),
    };
  }

  public toModel(date: NgbDateStruct | null): Dayjs | null {
    if (!date) {
      return null;
    }

    const dayjsDate = dayjs
      .utc()
      .year(date.year)
      .month(date.month - 1)
      .date(date.day)
      .hour(0)
      .minute(0)
      .second(0)
      .millisecond(0);

    return dayjsDate.isValid() ? dayjsDate : null;
  }
}

import { Injectable } from '@angular/core';
import { NgbDate, NgbDateStruct } from '@ng-bootstrap/ng-bootstrap';
import dayjs, { Dayjs } from 'dayjs';
import utc from 'dayjs/plugin/utc';
dayjs.extend(utc);

@Injectable({
  providedIn: 'root',
})
export class DateHelper {
  public formatDateToYYYYMMDD(date: Dayjs): string {
    return date.format('YYYYMMDD');
  }

  public fromNgbDateToUTCDate(date: NgbDate): Dayjs {
    const dayjsDate = dayjs
      .utc()
      .year(date.year)
      .month(date.month - 1)
      .date(date.day);

    return dayjsDate;
  }

  public fromDateToNgbDate(date: Dayjs): NgbDate {
    return new NgbDate(date.year(), date.month() + 1, date.date());
  }

  public padZero(value: number): string {
    return value < 10 ? `0${value}` : value.toString();
  }

  public formatNgbDate(date: NgbDateStruct): string {
    return `${this.padZero(date.day)}/${this.padZero(date.month)}/${date.year}`;
  }

  public compareDates(a: NgbDateStruct, b: NgbDateStruct): number {
    if (a.year !== b.year) {
      return a.year < b.year ? -1 : 1;
    }
    if (a.month !== b.month) {
      return a.month < b.month ? -1 : 1;
    }
    if (a.day !== b.day) {
      return a.day < b.day ? -1 : 1;
    }
    return 0;
  }

  public utcDayJs(year: number, month: number, day: number): Dayjs {
    return dayjs
      .utc()
      .year(year)
      .month(month - 1)
      .date(day);
  }

  public parseNaiveLocal(input: string): Dayjs {
    const clean = input.replace(/\sGMT[^\s)]+(?:\s+\([^)]*\))?$/, '');
    return dayjs(clean, 'ddd MMM DD YYYY HH:mm:ss', true);
  }

  public parseNaiveUtc(input: string): Dayjs {
    const d = this.parseNaiveLocal(input);
    return dayjs
      .utc()
      .year(d.year())
      .month(d.month())
      .date(d.date())
      .hour(d.hour())
      .minute(d.minute())
      .second(d.second())
      .millisecond(d.millisecond());
  }
}

