import { inject, Injectable, SecurityContext } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

import { RfListOption } from '../../components/rf-list/models/rf-list-option.model';

import { RfFilterType } from './filter.enum';
import { RfOptionsFilter } from './filter.model';

@Injectable({
  providedIn: 'root',
})
export class FilterService {
  private readonly sanitizer = inject(DomSanitizer);

  constructor() {}

  public filter(filterType: RfOptionsFilter, options: RfListOption[], filterValue: string): RfListOption[] {
    const method: RfFilterType = filterType?.type || RfFilterType.NORMAL;
    return this.strategies[method](options, filterValue);
  }

  private readonly normalizeWithTrim = (str: string): string =>
    str
      .normalize('NFD')
      .replaceAll(/[\u0300-\u036f]/g, '')
      .toLowerCase()
      .trim();

  private readonly normalizeWithoutTrim = (str: string): string =>
    str
      .normalize('NFD')
      .replaceAll(/[\u0300-\u036f]/g, '')
      .toLowerCase();

  public readonly strategies = {
    [RfFilterType.NORMAL]: (options: RfListOption[], filterValue: string): RfListOption[] => {
      const filterValueNormalized = this.normalizeWithTrim(filterValue);
      return options?.filter((o) =>
        this.normalizeWithTrim(o.content as unknown as string).includes(filterValueNormalized)
      );
    },
    [RfFilterType.MARKED]: (options: RfListOption[], filterValue: string): RfListOption[] => {
      const query = this.normalizeWithTrim(filterValue || '');

      return options
        ?.filter((o) => {
          const text = (o.content as string).replaceAll(/<[^>]*>/g, '');
          return this.normalizeWithTrim(text).includes(query);
        })
        .map((o) => ({
          ...o,
          content: this.highlightMatch(o.content, filterValue),
        }));
    },
  };
  private getIndexes(
    plainText: string,
    matchIndex: number,
    normalizedQuery: string
  ): { originalStart: number; originalEnd: number } {
    let visibleIndex = 0;
    let originalStart = -1;
    let originalEnd = -1;
    for (let i = 0; i < plainText.length; i++) {
      const currentChar = plainText[i];
      const normalizedChar = this.normalizeWithoutTrim(currentChar);
      if (visibleIndex === matchIndex && originalStart === -1) {
        originalStart = i;
      }
      if (visibleIndex === matchIndex + normalizedQuery.length - 1 && originalEnd === -1) {
        originalEnd = i + 1;
        break;
      }
      visibleIndex += normalizedChar.length;
    }
    return {
      originalStart,
      originalEnd,
    };
  }

  private getMarkedMatch(html: string, originalStart: number, originalEnd: number): string {
    let marked: string = '';
    let indexInPlain: number = 0;
    const regex: RegExp = /(<[^>]*>|[^<]+)/g;
    let match = regex.exec(html);

    while (match) {
      const chunk = match[0];
      if (chunk.startsWith('<')) {
        marked += chunk;
      } else {
        const chunkEnd = indexInPlain + chunk.length;
        if (indexInPlain <= originalStart && chunkEnd >= originalEnd) {
          const localStart = originalStart - indexInPlain;
          const localEnd = originalEnd - indexInPlain;
          marked +=
            chunk.slice(0, localStart) +
            `<mark class="list-filter-marked">${chunk.slice(localStart, localEnd)}</mark>` +
            chunk.slice(localEnd);
        } else {
          marked += chunk;
        }
        indexInPlain = chunkEnd;
      }
      match = regex.exec(html);
    }
    return marked;
  }

  private highlightMatch(safeHtml: SafeHtml, query: string): SafeHtml {
    if (!query?.trim()) return safeHtml;
    const html: string = this.sanitizer.sanitize(SecurityContext.HTML, safeHtml) ?? '';
    const plainText = html.replaceAll(/<[^>]*>/g, '');
    const normalizedPlain = this.normalizeWithoutTrim(plainText);
    const normalizedQuery = this.normalizeWithoutTrim(query.trim());
    const matchIndex = normalizedPlain.indexOf(normalizedQuery);
    if (matchIndex === -1) return safeHtml;
    const { originalStart, originalEnd } = this.getIndexes(plainText, matchIndex, normalizedQuery);
    if (originalStart === -1 || originalEnd === -1) return safeHtml;
    return this.getMarkedMatch(html, originalStart, originalEnd);
  }
}

import { Injectable, OnDestroy, Renderer2, RendererFactory2 } from '@angular/core';
import { Subject } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class GlobalEventsService implements OnDestroy {
  private readonly renderer: Renderer2;
  private readonly unlistenDown?: () => void;
  private readonly unlistenUp?: () => void;
  private readonly unlistenKeydown?: () => void;

  private readonly mousedownSubject = new Subject<MouseEvent>();
  private readonly mouseupSubject = new Subject<MouseEvent>();
  private readonly keydownSubject = new Subject<KeyboardEvent>();

  public readonly mousedown$ = this.mousedownSubject.asObservable();
  public readonly mouseup$ = this.mouseupSubject.asObservable();
  public readonly keydown$ = this.keydownSubject.asObservable();

  constructor(rendererFactory: RendererFactory2) {
    this.renderer = rendererFactory.createRenderer(null, null);

    this.unlistenDown = this.renderer.listen('window', 'mousedown', (e: MouseEvent) => {
      this.mousedownSubject.next(e);
    });

    this.unlistenUp = this.renderer.listen('window', 'mouseup', (e: MouseEvent) => {
      this.mouseupSubject.next(e);
    });

    this.unlistenKeydown = this.renderer.listen('window', 'keydown', (e: KeyboardEvent) => {
      this.keydownSubject.next(e);
    });
  }

  public ngOnDestroy(): void {
    this.unlistenDown?.();
    this.unlistenUp?.();
    this.unlistenKeydown?.();
  }
}

import { Injectable } from '@angular/core';

@Injectable({
  providedIn: 'root',
})
export class IdService {
  public generateRandomId(): string {
    return Array.from({ length: 8 }, () => String.fromCodePoint(97 + Math.floor(Math.random() * 26))).join('');
  }
}

import { HttpClient } from '@angular/common/http';
import { inject, Injectable, Injector, signal } from '@angular/core';
// All comments in English (project rule)
import { TranslateService } from '@ngx-translate/core';
import { Observable, of } from 'rxjs';
import { catchError, map, shareReplay } from 'rxjs/operators';

import { STORY_DICTIONARY, TRANSLATION_BASE_URL } from './tokens';

export type StoryDictionary = Record<string, string>;

/**
 * Storybook translation loader (DS/BC stories).
 *
 * Responsibilities:
 * - Loads keys for one or more modules via TRANSLATION_BASE_URL (GetByCultureAndKeys), when available.
 * - Accepts the AutoTranslateDirective shape ({ moduleName: string | string[] }) as well as plain forms ('Common', ['Common']) and { module|modules|keys }.
 * - Merges dictionaries as: API > STORY_DICTIONARY (mock). Converts flat keys ("Common.A11y.Foo": "...") into the nested object expected by ngx-translate.
 * - Applies dictionaries with setTranslation(..., merge=true) and ensures the active language via setFallbackLang(...) + use(...). It does NOT call resetLang (to avoid clearing the store).
 * - Reads TRANSLATION_BASE_URL and STORY_DICTIONARY from the module injector at call time, so per-story overrides are honored (no global provider needed).
 * - Memoizes by (lang|keys|baseUrl|mockSig) to prevent duplicate HTTP calls.
 */

@Injectable({ providedIn: 'any' })
export class StoryModuleTranslationService {
  // Cache per (lang + modules + baseUrl + mock signature)
  private readonly cache = new Map<string, Observable<unknown>>();
  // Track loaded modules for quick checks (module name as key)
  private readonly loadedModules = new Set<string>();
  private readonly loadedModulesSignal = signal<Record<string, boolean>>({});
  public readonly loadedModules$ = this.loadedModulesSignal.asReadonly();

  private readonly translate = inject(TranslateService);
  private readonly http = inject(HttpClient, { optional: true });
  private readonly injector = inject(Injector);

  /** Resolve tokens at call time so per-story overrides are visible. */
  private resolveConfig(): { baseUrl?: string; mock: StoryDictionary } {
    const base = this.injector.get(TRANSLATION_BASE_URL, undefined);
    const dict = this.injector.get(STORY_DICTIONARY, {} as StoryDictionary);
    return { baseUrl: base ?? undefined, mock: dict ?? {} };
  }

  private applyDict(lang: string, dict: Record<string, string>): void {
    if (!dict || !Object.keys(dict).length) return;
    this.ensureLangActive(lang);
    this.translate.setTranslation(lang, this.toNested(dict), true);
  }

  private ensureLangActive(lang: string): void {
    this.translate.setFallbackLang(lang);
    if (this.translate.getCurrentLang && this.translate.getCurrentLang() !== lang) {
      this.translate.use(lang);
    }
  }

  /** Accepts: 'Common' | ['Common','Navigation'] | { module: 'Common' } | { moduleName: 'Common' | string[] } | { keys: [...] } */
  public loadModuleTranslations(spec: unknown): Observable<unknown> {
    const lang = this.translate.getCurrentLang() || this.translate.getFallbackLang() || 'es-ES';

    // Read tokens now (not at construction time)
    const { baseUrl, mock } = this.resolveConfig();

    const keysCsv = this.normalizeModules(spec, mock);

    console.log('[SB-i18n] start', {
      lang,
      keysCsv,
      hasHttp: !!this.http,
      baseUrl,
      mockPreview: Object.fromEntries(Object.entries(mock).slice(0, 50)),
    });

    // NO KEYS: No keys → apply mock only (if present) and complete
    if (!keysCsv) {
      if (Object.keys(mock).length) {
        this.applyDict(lang, mock);
      } else {
        // Helpful for diagnosing missing directive spec in stories
        // (e.g., <ng-container [appAutoTranslate]="'Common'"></ng-container> not present)
        console.warn('[i18n] No keys to load and no mock provided.');
      }
      return of({ success: true, data: {} } as const);
    }

    const moduleNames = keysCsv.split(',').map((k) => k.trim());

    // Stronger cache key includes baseUrl and mock signature to avoid poisoned cache reuse
    const mockSig = Object.keys(mock).length; // could be replaced by a hash if needed
    const apiSig = baseUrl ?? 'no-api';
    const cacheKey = `${lang}|${keysCsv}|${apiSig}|mock:${mockSig}`;

    const cached = this.cache.get(cacheKey);
    if (cached) {
      console.log('[SB-i18n] cache hit', cacheKey);
      return cached;
    }

    // MOCK-ONLY: If no API available, apply mock and cache
    if (!this.http || !baseUrl) {
      const done$ = of(null).pipe(
        map(() => {
          this.applyDict(lang, mock);
          // Mark modules as loaded
          moduleNames.forEach((name) => this.loadedModules.add(name));
          this.loadedModulesSignal.update((current) => {
            const updated = { ...current };
            moduleNames.forEach((name) => {
              updated[name] = true;
            });
            return updated;
          });
          return { success: true, data: {} } as const;
        }),
        shareReplay({ bufferSize: 1, refCount: false })
      );
      this.cache.set(cacheKey, done$);
      return done$;
    }

    // API: API request and merge: API > mock
    const url = `${baseUrl.replace(/\/$/, '')}/GetByCultureAndKeys`;

    if (Object.keys(mock).length) {
      this.applyDict(lang, mock);
    }

    const req$ = this.http.get<Record<string, string>>(url, { params: { culture: lang, keys: keysCsv } }).pipe(
      catchError((err) => {
        console.warn('[SB-i18n] api error, fallback to mock', err);
        return of({} as Record<string, string>);
      }),
      map((api) => {
        const hasApi = api && Object.keys(api).length > 0;

        if (hasApi) {
          this.applyDict(lang, api);

          if (Object.keys(mock).length) {
            this.applyDict(lang, mock);
          }
          console.log('[SB-i18n] api merged (api→mock), keys:', Object.keys(api).length);
        } else {
          console.log('[SB-i18n] api returned empty, keeping mock only');
        }

        // Mark modules as loaded
        moduleNames.forEach((name) => this.loadedModules.add(name));
        this.loadedModulesSignal.update((current) => {
          const updated = { ...current };
          moduleNames.forEach((name) => {
            updated[name] = true;
          });
          return updated;
        });

        return { success: true, data: (api && Object.keys(api).length ? api : {}) } as const;
      }),
      shareReplay({ bufferSize: 1, refCount: false })
    );

    this.cache.set(cacheKey, req$);
    return req$;
  }

  /** Converts the directive arg into a CSV list of module names. */
  private normalizeModules(spec: unknown, mock: StoryDictionary): string {
    if (typeof spec === 'string') return spec;
    if (Array.isArray(spec)) return spec.join(',');
    if (spec && typeof spec === 'object') {
      const o = spec as any;

      // Support AutoTranslateDirective shape
      if (typeof o.moduleName === 'string') return o.moduleName;
      if (Array.isArray(o.moduleName)) return o.moduleName.join(',');

      if (typeof o.module === 'string') return o.module;
      if (Array.isArray(o.modules)) return o.modules.join(',');
      if (Array.isArray(o.keys)) return o.keys.join(',');
    }
    const firstKey = Object.keys(mock)[0];
    if (firstKey?.includes('.')) return firstKey.split('.')[0];
    return '';
  }

  // Treat folder markers (null/empty, no dot) as branches; only '.' defines hierarchy.
  // If a leaf clashes with a branch, prefer the branch and (optionally) preserve the old leaf in ._value.
  // Underscores are literal (never split).
  private toNested(dict: Record<string, string | null | undefined>): Record<string, any> {
    const root: Record<string, any> = {};
    const isBranch = (v: unknown): v is Record<string, any> => !!v && typeof v === 'object' && !Array.isArray(v);

    for (const [fullKey, rawValue] of Object.entries(dict)) {
      const parts = fullKey.split('.');
      let node: any = root;

      for (let i = 0; i < parts.length - 1; i++) {
        const k = parts[i];

        if (!isBranch(node[k])) {
          if (node[k] !== undefined) {
            node[k] = { ['_value']: node[k] };
          } else {
            node[k] = {};
          }
        }
        node = node[k];
      }

      const leaf = parts[parts.length - 1];

      const isFolderMarker = (rawValue === null || rawValue === '' || rawValue === undefined) && parts.length === 1;
      if (isFolderMarker) {
        if (!isBranch(node[leaf])) node[leaf] = {};
        continue;
      }

      if (isBranch(node[leaf])) {
        node[leaf]['_value'] = rawValue ?? ''; // <- corchetes

        console.warn('[SB-i18n] Leaf collision on object. Stored at', `${fullKey}._value`);
      } else {
        node[leaf] = rawValue ?? '';
      }
    }
    return root;
  }

  /**
   * Checks if a module has been loaded previously.
   * @param moduleName Name of the module to check
   * @returns True if the module has been loaded previously
   */
  public isModuleLoaded(moduleName: string): boolean {
    return this.loadedModules.has(moduleName);
  }
}

import { inject, Injectable } from '@angular/core';
import { SummaryDataRenderer } from '@dcx/ui/design-system';
import { CultureServiceEx, EnumSeparators, TextHelperService } from '@dcx/ui/libs';
import dayjs from 'dayjs';
import 'dayjs/locale/es';
import 'dayjs/locale/fr';
import 'dayjs/locale/pt';

import { RfListOption } from '../../components/rf-list/models/rf-list-option.model';
import { RfFormControl } from '../../extensions/components/rf-form-control.component';
import { RfFormGroup } from '../../extensions/components/rf-form-group.component';
import { RfFormBuilderComponent } from '../../form-builder/rf-form-builder/rf-form-builder.component';

import { DATEPICKER_COMPONENTS, UNIQUE_COMPONENTS } from './constants/summary-special-cases.constant';
import { SummaryBuilderAddition, SummaryBuilderAdditions } from './models/summary-builder-addition.model';

@Injectable({
  providedIn: 'root',
})
export class SummaryBuilderService {
  private _form!: RfFormGroup;
  private readonly cultureServiceEx = inject(CultureServiceEx);
  private readonly textHelperService = inject(TextHelperService);

  constructor() {
    dayjs.locale(this.cultureServiceEx.getCulture());
  }

  private getLabelsFromSelectedValues(parsedValue: any, rfComponent: any): string {
    if (!Array.isArray(rfComponent)) {
      return String(parsedValue);
    }

    const values = Array.isArray(parsedValue) ? parsedValue : [parsedValue];
    const labels = this.mapValuesToLabels(values, rfComponent);

    return labels.length > 0 ? labels.join(', ') : String(parsedValue);
  }

  private mapValuesToLabels(values: string[], components: any[]): string[] {
    return values.reduce<string[]>((acc, val) => {
      const match = components.find((c) => typeof c.value === 'function' && c.value() === val);

      if (match) {
        const label = typeof match.label === 'function' ? match.label() : '';
        if (label) acc.push(label);
      }

      return acc;
    }, []);
  }

  private isDateRange(value: any): value is { startDate: any; endDate: any } {
    return value && typeof value === 'object' && 'startDate' in value && 'endDate' in value;
  }

  private isDayjsObject(value: any): boolean {
    return value && typeof value.format === 'function' && '$isDayjsObject' in value;
  }

  private getSummaryDataFromStrategy(form: RfFormGroup, rawValue: any, key: string): { label: string; value: string } {
    const rfComponent = (form.controls[key] as RfFormControl)?.rfComponent;
    const rfTypeClass = Array.isArray(rfComponent) ? rfComponent[0]?.rfTypeClass : rfComponent?.rfTypeClass;

    if (!rfTypeClass) return rawValue[key];

    return this.getStrategy(rfTypeClass, rawValue, key, rfComponent);
  }

  private parseDatepicker(parsedValue: any, key: string, rfComponent: any): { label: string; value: string } {
    //Update to a dynamic strategy from country when implementing CMS
    let dateValue = '';
    if (this.isDateRange(parsedValue)) {
      dateValue = `${parsedValue.startDate.format('MMMM D,YYYY')} - ${parsedValue.endDate.format('MMMM D,YYYY')}`;
    } else if (this.isDayjsObject(parsedValue)) {
      dateValue = parsedValue.format(this.cultureServiceEx.getUserCulture().longDateFormat);
    }

    const label = this.resolveLabel(rfComponent.animatedLabel, rfComponent.title, key);
    return { value: dateValue, label };
  }

  private parseCheckbox(parsedValue: any[], key: string, rfComponent: any): { label: string; value: string } {
    const value = parsedValue.length > 0 ? this.getLabelsFromSelectedValues(parsedValue, rfComponent) : '';
    const label = this.resolveLabel(rfComponent[0]?.legend, null, key);
    return { value, label };
  }

  private parseRadio(parsedValue: any, key: string, rfComponent: any): { label: string; value: string } {
    const hasValue = parsedValue !== null && parsedValue !== undefined && parsedValue !== '';
    const value = hasValue ? this.getLabelsFromSelectedValues(parsedValue, rfComponent) : '';
    const label = this.resolveLabel(rfComponent[0]?.legend, null, key);
    return { value, label };
  }

  private parseSelect(parsedValue: any, key: string, rfComponent: any): { label: string; value: string } {
    let value = '';
    const { options } = rfComponent;

    if (typeof options === 'function') {
      const option = options().find((opt: RfListOption) => opt.value === parsedValue);
      value = option?.content ?? '';
    } else {
      value = this.getLabelsFromSelectedValues(parsedValue, rfComponent);
    }

    const label = this.resolveLabel(rfComponent.animatedLabel, null, key);
    return { value, label };
  }

  private parsePhone(parsedValue: any, key: string, rfComponent: any): { label: string; value: string } {
    const prefix: string = parsedValue?.prefix?.replace(/-.*$/, '');
    const value = this.textHelperService.concatValidParts([prefix ?? '', parsedValue?.phone ?? '']);
    const label = this.resolveLabel(rfComponent.title, null, key);
    return { value: value || EnumSeparators.DASH, label };
  }

  private parseDefault(parsedValue: any, key: string, rfComponent: any): { label: string; value: string } {
    const hasValue = parsedValue !== null && parsedValue !== undefined && parsedValue !== '';
    const value = hasValue ? this.getLabelsFromSelectedValues(parsedValue, rfComponent) : '';
    const label = this.resolveLabel(rfComponent.animatedLabel, rfComponent.label, key);
    return { value, label };
  }

  private resolveLabel(fn1?: (() => string) | null, fn2?: (() => string) | null, fallback: string = ''): string {
    if (typeof fn1 === 'function') return fn1();
    if (typeof fn2 === 'function') return fn2();
    return fallback;
  }

  private getStrategy(
    rfTypeClass: string,
    rawValue: any,
    key: string,
    rfComponent: any
  ): { label: string; value: string } {
    const parsedValue = rawValue[key];

    if (DATEPICKER_COMPONENTS.includes(rfTypeClass)) {
      return this.parseDatepicker(parsedValue, key, rfComponent);
    }

    switch (rfTypeClass) {
      case UNIQUE_COMPONENTS.checkbox:
        return this.parseCheckbox(parsedValue, key, rfComponent);

      case UNIQUE_COMPONENTS.radio:
        return this.parseRadio(parsedValue, key, rfComponent);

      case UNIQUE_COMPONENTS.select:
        return this.parseSelect(parsedValue, key, rfComponent);

      case UNIQUE_COMPONENTS.prefixPhone:
        return this.parsePhone(parsedValue, key, rfComponent);

      default:
        return this.parseDefault(parsedValue, key, rfComponent);
    }
  }

  public calculateConfig(
    form: RfFormGroup | RfFormBuilderComponent,
    additions: SummaryBuilderAdditions,
    subtractions: string[]
  ): Record<string, SummaryDataRenderer> {
    this.setForm(form);
    const rawValue = this._form?.getRawValue();
    const summary = this.buildBaseSummary(rawValue);
    const entries = Object.entries(summary);

    this.applyAdditions(entries, additions, rawValue);

    const summaryWithAdditions = Object.fromEntries(entries);

    this.applySubtractions(summaryWithAdditions, subtractions);
    return summaryWithAdditions;
  }

  private setForm(form: RfFormGroup | RfFormBuilderComponent): void {
    if (form instanceof RfFormBuilderComponent) {
      this._form = form.form as RfFormGroup;
      return;
    }

    if (form instanceof RfFormGroup) {
      this._form = form;
    }
  }

  private buildBaseSummary(rawValue: Record<string, unknown>): Record<string, SummaryDataRenderer> {
    const summary: Record<string, SummaryDataRenderer> = {};

    for (const key in rawValue) {
      if (!rawValue.hasOwnProperty(key)) continue;
      summary[key] = this.getSummaryDataFromStrategy(this._form, rawValue, key);
    }

    return summary;
  }

  private applyAdditions(
    entries: [string, SummaryDataRenderer][],
    additions: SummaryBuilderAdditions,
    rawValue: Record<string, unknown>
  ): void {
    if (!additions) return;

    for (const key in additions) {
      if (!additions.hasOwnProperty(key)) continue;

      const addition = additions[key];
      const pair = this.createAdditionPair(key, addition, rawValue);
      this.insertAdditionPair(entries, pair, addition);
    }
  }

  private createAdditionPair(
    key: string,
    addition: SummaryBuilderAddition,
    rawValue: Record<string, unknown>
  ): [string, { label: string; value: string }] {
    const computedLabel = addition?.label ? addition.label(rawValue) : key;
    const computedValue = addition?.value ? addition.value(rawValue) : '';

    return [
      key,
      {
        label: computedLabel == null ? key : String(computedLabel),
        value: computedValue == null ? '' : String(computedValue),
      },
    ];
  }

  private insertAdditionPair(
    entries: [string, SummaryDataRenderer][],
    pair: [string, SummaryDataRenderer],
    addition: SummaryBuilderAddition
  ): void {
    if (!addition.position) {
      entries.push(pair);
      return;
    }

    const targetIndex = entries.findIndex(([k]) => k === addition.position?.key);

    if (targetIndex < 0) {
      entries.push(pair);
      return;
    }

    const insertIndex = addition.position.after ? targetIndex + 1 : targetIndex;
    entries.splice(insertIndex, 0, pair);
  }

  private applySubtractions(summary: Record<string, SummaryDataRenderer>, subtractions: string[]): void {
    if (!subtractions) return;

    for (const key of subtractions) {
      if (summary.hasOwnProperty(key)) {
        delete summary[key];
      }
    }
  }
}

