import { type Provider, type EnvironmentProviders } from '@angular/core';
import { registerLocaleData } from '@angular/common';
import localeDe from '@angular/common/locales/de';
import localeGr from '@angular/common/locales/el';
import localeEs from '@angular/common/locales/es';
import localeFr from '@angular/common/locales/fr';
import localeIt from '@angular/common/locales/it';
import localeKk from '@angular/common/locales/kk';
import localePt from '@angular/common/locales/pt';
import localeRu from '@angular/common/locales/ru';
import localeTr from '@angular/common/locales/tr';
import { applicationConfig, type Preview } from '@storybook/angular';
import { provideHttpClient, withInterceptorsFromDi } from '@angular/common/http';
import { TranslateLoader, provideTranslateService, provideTranslateLoader } from '@ngx-translate/core';
import { ModuleTranslationService } from '@dcx/module/translation';
import { Observable, of } from 'rxjs';
import { withStoryTranslationsAuto } from '../i18n/with-story-translations-auto.decorator';
import { StoryModuleTranslationService } from '../i18n/story-module-translation.service';
import { TRANSLATION_BASE_URL, STORY_DICTIONARY } from '../i18n/tokens';
import { initKeyboardFocusDetection } from '@dcx/ui/libs';

/**
 * Empty loader — translations are injected later by a per-story provider.
 * This class is exported to avoid duplication across preview.ts files.
 */
export class EmptyLoader implements TranslateLoader {
  getTranslation(_lang: string): Observable<Record<string, string>> {
    return of({});
  }
}

/**
 * Default translation base URL used across all Storybooks
 * Can be overridden in individual preview.ts files if needed
 */
export const DEFAULT_TRANSLATION_BASE_URL = 'https://av-booking-test2.newshore.es/configuration/api/v1/UI_PLUS/Translation';

/**
 * Registers all Angular locale data for internationalization support.
 * This enables proper formatting of dates, numbers, and currencies across all supported locales.
 *
 * Call this once at the beginning of your preview.ts file:
 * ```typescript
 * import { registerAllLocales } from '@dcx/ui/storybook-utils';
 * registerAllLocales();
 * ```
 */
export function registerAllLocales(): void {
  const locales = [
    { data: localeDe, code: 'de-DE' },
    { data: localeEs, code: 'es-ES' },
    { data: localeIt, code: 'it-IT' },
    { data: localePt, code: 'pt-BR' },
    { data: localeRu, code: 'ru-RU' },
    { data: localeTr, code: 'tr-TR' },
    { data: localeFr, code: 'fr-FR' },
    { data: localeKk, code: 'kk-KZ' },
    { data: localeGr, code: 'el-GR' },
  ];

  locales.forEach(({ data, code }) => registerLocaleData(data, code));
}

/**
 * Creates shared base providers for Storybook decorators
 * This is a helper to avoid duplicating the base provider setup
 */
export function createBaseProviders(): (Provider | EnvironmentProviders)[] {
  return [
    provideHttpClient(withInterceptorsFromDi()),
    ...provideTranslateService({ lang: 'es-ES', fallbackLang: 'es-ES' }),
    provideTranslateLoader(EmptyLoader),
    {
      provide: TRANSLATION_BASE_URL,
      useValue: DEFAULT_TRANSLATION_BASE_URL,
    },
    { provide: STORY_DICTIONARY, useValue: {} },
    // Default translation service used by all modules
    // Can be overridden by passing a different provider in additionalProviders
    { provide: ModuleTranslationService, useClass: StoryModuleTranslationService },
  ];
}

/**
 * Creates shared decorators with optional additional providers
 * Use this to extend the base configuration with module-specific providers
 *
 * @param additionalProviders - Optional array of additional Angular providers
 * @param additionalDecorators - Optional array of additional Storybook decorators
 * @returns Array of Storybook decorators
 *
 * @example
 * ```typescript
 * // Basic usage - no additional providers needed
 * const decorators = createSharedDecorators();
 *
 * // With additional providers
 * import { AuthService } from '@dcx/ui/libs';
 * const decorators = createSharedDecorators([
 *   { provide: AuthService, useClass: AuthServiceMock }
 * ]);
 * ```
 */
export function createSharedDecorators(
  additionalProviders: (Provider | EnvironmentProviders)[] = [],
  additionalDecorators: any[] = []
): any[] {
  return [
    applicationConfig({
      providers: [
        ...createBaseProviders(),
        ...additionalProviders,
      ],
    }),
    withStoryTranslationsAuto,
    ...additionalDecorators,
  ];
}

/**
 * Shared decorators used across all Storybook instances
 * Uses the createSharedDecorators helper for consistency
 */
export const sharedDecorators = createSharedDecorators();

/**
 * Shared parameters used across all Storybook instances
 */
export const sharedParameters = {
  controls: {
    expanded: true,
    matchers: {
      color: /(background|color)$/i,
      date: /Date$/,
    },
  },
  // Disable API calls in Storybook by default, use mocks instead
  // Individual stories can override with i18n: { api: true } if needed
  i18n: {
    api: false,
  },
  // Standard story sort order for all modules
  options: {
    storySort: {
      method: 'alphabetical' as const,
      order: ['Overview', 'Guidelines', 'Atoms', 'Molecules', 'Organisms', 'Main'],
      locales: 'en-US',
    },
  },
};

/**
 * Shared initial globals
 */
export const sharedInitialGlobals = {
  backgrounds: { grid: false },
};

/**
 * Complete shared preview configuration
 * This can be spread into any module's preview.ts file
 */
export const sharedPreviewConfig: Preview = {
  decorators: sharedDecorators,
  parameters: sharedParameters,
  // Note: initialGlobals is intentionally not included here as it's module-specific
};

/**
 * Initialize shared Storybook functionality
 * This is called automatically when this module is imported.
 * No need to call it explicitly in your preview.ts files.
 *
 * @deprecated Use the automatic initialization by importing sharedPreviewConfig.
 * This function is kept for backward compatibility but will be removed in future versions.
 */
export function initializeStorybook(): void {
  initKeyboardFocusDetection();
}

// Auto-initialize when this module is loaded
// This runs once per Storybook instance, avoiding code duplication
initKeyboardFocusDetection();

import { importProvidersFrom } from '@angular/core';
import { ModalDialogService } from '@dcx/ui/design-system';
import {
  BUTTON_CONFIG,
  ComposerService,
  ConfigService,
  CookiesStore,
  DEFAULT_CONFIG_BUTTON,
  EventBusService,
  EXCLUDE_SESSION_EXPIRED_URLS,
  GenerateIdPipe,
  LoggerService,
  NotificationService,
  RedirectService,
  TIMEOUT_REDIRECT,
} from '@dcx/ui/libs';
import { CookieServiceFake, EventBusServiceFake, LoggerServiceFake } from '@dcx/ui/mock-repository';
import { NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { TranslateLoader, TranslateModule } from '@ngx-translate/core';
import { Observable, of } from 'rxjs';

// Fake TranslateLoader for Storybook
class FakeTranslateLoader implements TranslateLoader {
  public getTranslation(): Observable<Record<string, string>> {
    return of({});
  }
}

// Regular providers for component-level injection
export const STORYBOOK_PROVIDERS = [
  ConfigService,
  ComposerService,
  GenerateIdPipe,
  NgbModal,
  ModalDialogService,
  NotificationService,
  RedirectService,
  CookiesStore,
  {
    provide: EXCLUDE_SESSION_EXPIRED_URLS,
    useValue: [],
  },
  {
    provide: TIMEOUT_REDIRECT,
    useValue: '/',
  },
  {
    provide: CookiesStore,
    useClass: CookieServiceFake,
  },
  {
    provide: EventBusService,
    useClass: EventBusServiceFake,
  },
  {
    provide: LoggerService,
    useClass: LoggerServiceFake,
  },
  {
    provide: BUTTON_CONFIG,
    useValue: DEFAULT_CONFIG_BUTTON,
  },
];

// Environment providers for application-level injection
export const STORYBOOK_ENVIRONMENT_PROVIDERS = [
  importProvidersFrom(
    TranslateModule.forRoot({
      loader: {
        provide: TranslateLoader,
        useClass: FakeTranslateLoader,
      },
    })
  ),
];

import { EventEmitter } from '@angular/core';
import { AsyncValidatorFn, FormControl, ValidatorFn, Validators } from '@angular/forms';

import { Opts } from '../models/rf-form-control-opt.model';
import { RfComponentTypes, RfValidatorsConfig } from '../types/rf-form-control-validations.types';

/**
 * `RfFormControl` extends Angular's `FormControl` by adding:
 * - Emission of custom events on state changes (touched, dirty, value set, etc.).
 * - Storage of custom validators and "required" state.
 * - Support for composite validator configurations (array or object).
 *
 * This control is designed to integrate with advanced reactive form components
 * and enable tighter feedback between components and controls.
 *
 * @template FormState The type of the control's value.
 */
export class RfFormControl<FormState = any> extends FormControl {
  /** Emits when the control is marked as touched. */
  public onMarkAsTouched = new EventEmitter<void>();

  /** Emits when the control and all children are marked as touched. */
  public onMarkAllAsTouched = new EventEmitter<void>();

  /** Emits when the control is marked as untouched. */
  public onMarkAsUntouched = new EventEmitter<void>();

  /** Emits when the control is marked as dirty. */
  public onMarkAsDirty = new EventEmitter<void>();

  /** Emits when the control and all children are marked as dirty. */
  public onMarkAllAsDirty = new EventEmitter<void>();

  /** Emits when the control is marked as pristine. */
  public onMarkAsPristine = new EventEmitter<void>();

  /** Emits when the control's value is updated via `setValue()`. */
  public onSetValue = new EventEmitter<FormState>();

  /** Indicates whether the control is required based on its validator configuration. */
  public isRequired: boolean = false;

  /** Reference to the component(s) associated with this control. */
  public rfComponent!: RfComponentTypes | RfComponentTypes[];

  /** Tracks whether the control has been submitted (for internal form builder use). */
  private _submitted = false;

  /**
   * Gets whether the control has been submitted.
   */
  public get submitted(): boolean {
    return this._submitted;
  }

  /**
   * Sets whether the control has been submitted.
   */
  public set submitted(value: boolean) {
    this._submitted = value;
  }

  /**
   * Stores the custom validators assigned to the control.
   * This can be a single validator, an array, or a composite object,
   * and is used to retrieve or reapply validation logic as needed.
   */
  private customValidators: RfValidatorsConfig = null;

  /**
   * Creates a new instance of RfFormControl.
   *
   * @param formState - Initial control value or FormControlState.
   * @param validators - One or more validators, or a composite validator config object.
   * @param asyncValidator - Optional asynchronous validators.
   */
  constructor(
    formState?: FormState,
    validators?: RfValidatorsConfig,
    asyncValidator?: AsyncValidatorFn | AsyncValidatorFn[] | null
  ) {
    const processedValidators = Array.isArray(validators) ? validators : null;
    super(formState, processedValidators, asyncValidator);
    this.setCustomValidators(validators);
    this.setIfFieldIsRequired(validators);
  }

  /**
   * Sets the internal custom validator configuration.
   *
   * @param validators - Custom validator config.
   */
  public setCustomValidators(validators?: RfValidatorsConfig): void {
    this.customValidators = validators ?? {};
  }

  /**
   * Retrieves the stored custom validator configuration.
   *
   * @returns The custom validator config used by the control.
   */
  public getCustomValidators(): RfValidatorsConfig {
    return this.customValidators;
  }

  /**
   * Sets the control's value and emits the `onSetValue` event
   * if `emitEvent` is not explicitly disabled.
   *
   * @param value - New control value.
   * @param opts - Optional options for `setValue()`.
   */
  public override setValue(value: FormState, opts?: Parameters<FormControl<FormState>['setValue']>[1]): void {
    super.setValue(value, opts);
    if (this.canISendEvent(opts)) {
      this.onSetValue.emit(value);
    }
  }

  /**
   * Marks the control as touched and emits the `onMarkAsTouched` event.
   */
  public override markAsTouched(opts?: Opts): void {
    super.markAsTouched(opts);
    if (this.canISendEvent(opts)) {
      this.onMarkAsTouched.emit();
    }
  }

  /**
   * Marks the control and descendants as touched and emits the corresponding event.
   */
  public override markAllAsTouched(opts?: Opts): void {
    super.markAllAsTouched(opts);
    if (this.canISendEvent(opts)) {
      this.onMarkAllAsTouched.emit();
    }
  }

  /**
   * Marks the control as untouched and emits the `onMarkAsUntouched` event.
   */
  public override markAsUntouched(opts?: Opts): void {
    super.markAsUntouched(opts);
    if (this.canISendEvent(opts)) {
      this.onMarkAsUntouched.emit();
    }
  }

  /**
   * Marks the control as dirty and emits the `onMarkAsDirty` event.
   */
  public override markAsDirty(opts?: Opts): void {
    super.markAsDirty(opts);
    if (this.canISendEvent(opts)) {
      this.onMarkAsDirty.emit();
    }
  }

  /**
   * Marks the control as pristine and emits the `onMarkAsPristine` event.
   */
  public override markAsPristine(opts?: Opts): void {
    super.markAsPristine(opts);
    if (this.canISendEvent(opts)) {
      this.onMarkAsPristine.emit();
    }
  }

  /**
   * Marks the control and descendants as dirty and emits the corresponding event.
   */
  public markAllAsDirty(opts?: Opts): void {
    this.markAsDirty({ emitEvent: false });
    if (this.canISendEvent(opts)) {
      this.onMarkAllAsDirty.emit();
    }
  }

  /**
   * Determines whether event emitters should be triggered based on the given options.
   *
   * @param opts - Options passed to the form state method.
   * @returns True if the event should be emitted.
   */
  private canISendEvent(opts?: Opts): boolean {
    return !opts || Object.keys(opts).length === 0 || opts.emitEvent === true || opts.onlySelf === true;
  }

  /**
   * Checks whether the field should be considered required by inspecting its validators.
   *
   * @param validators - The validator config to evaluate.
   */
  private setIfFieldIsRequired(validators?: RfValidatorsConfig): void {
    const requiredFn = Validators.required;
    if (validators) {
      this.isRequired = this.containsRequiredValidator(validators, requiredFn);
    }
  }

  /**
   * Checks whether a given validator config contains the `Validators.required` function.
   *
   * @param config - The validator config.
   * @param requiredFn - The `Validators.required` reference.
   * @returns True if found.
   */
  private containsRequiredValidator(config: RfValidatorsConfig, requiredFn: ValidatorFn): boolean {
    if (!config) return false;

    if (typeof config === 'function') {
      return this.isSameValidator(config, requiredFn);
    }

    if (Array.isArray(config)) {
      return config.some((v) => this.isSameValidator(v, requiredFn));
    }

    if (typeof config === 'object') {
      return Object.values(config).some((validatorList: ValidatorFn[]) =>
        validatorList.some((v) => this.isSameValidator(v, requiredFn))
      );
    }

    return false;
  }

  /**
   * Compares two validators for identity or matching function name.
   *
   * @param a - Validator A.
   * @param b - Validator B.
   * @returns True if both are considered the same.
   */
  private isSameValidator(a: ValidatorFn, b: ValidatorFn): boolean {
    return a === b || a.name === b.name;
  }

  /**
   * Performs a deep comparison between two objects or values.
   *
   * @param a - First value.
   * @param b - Second value.
   * @returns True if deeply equal.
   */
  private deepEqual(a: any, b: any): boolean {
    if (a === b) return true;

    if (typeof a !== typeof b) return false;
    if (a === null || b === null) return false;

    if (Array.isArray(a) && Array.isArray(b)) {
      if (a.length !== b.length) return false;
      return a.every((item, i) => this.deepEqual(item, b[i]));
    }

    if (typeof a === 'object' && typeof b === 'object') {
      const aKeys = Object.keys(a);
      const bKeys = Object.keys(b);
      if (aKeys.length !== bKeys.length) return false;
      return aKeys.every((key) => b.hasOwnProperty(key) && this.deepEqual(a[key], b[key]));
    }

    return false;
  }
}

import { signal } from '@angular/core';
import { AbstractControl, AsyncValidatorFn, FormArray, FormGroup, ValidatorFn } from '@angular/forms';

import { RfErrorDisplayModes } from '../../abstract/enums/rf-base-reactive-display-mode.enum';

import { RfFormControl } from './rf-form-control.component';

/**
 * `RfFormGroup` extends Angular's `FormGroup` by:
 * - Tracking the form name and preventing duplicate names (unless explicitly allowed).
 * - Managing a shared `displayErrorsMode` for all contained controls.
 * - Providing recursive methods to mark controls as dirty/touched.
 * - Supporting state propagation for `submitted` and `debug` flags.
 *
 * This utility is especially useful in complex dynamic forms where
 * error handling and state syncing need to be centralized.
 */
export class RfFormGroup extends FormGroup {
  /** The name of this form group (used for identification and tracking). */
  public formName: string;

  /** Error display mode shared across child components. */
  public displayErrorsMode: RfErrorDisplayModes | undefined | null;
  public readonly valueSignal = signal(this.value);
  public readonly statusSignal = signal(this.status);

  /**
   * Static registry to track already used form names and avoid duplication.
   */
  private static readonly registeredFormNames = new Set<string>();

  /**
   * Constructs a new `RfFormGroup`.
   *
   * @param formName - A unique form name or a config object with `name` and `allowRepeat`.
   * @param controls - The child controls of the form group.
   * @param validators - Optional synchronous validators.
   * @param asyncValidators - Optional asynchronous validators.
   * @param displayErrorsMode - Default error display mode for this form.
   */
  constructor(
    formName: string | { name: string; allowRepeat: boolean },
    controls: { [key: string]: AbstractControl },
    validators?: ValidatorFn | ValidatorFn[] | null,
    asyncValidators?: AsyncValidatorFn | AsyncValidatorFn[] | null,
    displayErrorsMode?: RfErrorDisplayModes | null
  ) {
    const name = typeof formName === 'string' ? formName : formName.name;
    const allowRepeat = typeof formName === 'string' ? false : formName.allowRepeat;

    if (!allowRepeat && RfFormGroup.registeredFormNames.has(name)) {
      console.warn(`Form with name "${name}" already exists.`);
    }

    super(controls, validators, asyncValidators);

    this.formName = name;
    this.displayErrorsMode = displayErrorsMode;

    if (!allowRepeat) {
      RfFormGroup.registeredFormNames.add(name);
    }

    this.valueChanges.subscribe(() => this.valueSignal.set(this.value));
    this.statusChanges.subscribe(() => this.statusSignal.set(this.status));
  }

  /** Tracks whether this form has been submitted. */
  private _submitted = false;

  /**
   * Gets the submitted status of the form.
   */
  public get submitted(): boolean {
    return this._submitted;
  }

  /**
   * Sets the submitted status and propagates it to child controls.
   */
  public set submitted(value: boolean) {
    this._submitted = value;
    this.changeSubmitedStatus();
  }

  /**
   * Marks all controls (and nested controls) as dirty.
   *
   * @param control - The root control to mark. Defaults to `this`.
   */
  public markAllAsDirty(control: AbstractControl = this): void {
    if ((control as RfFormGroup | FormGroup | FormArray).controls) {
      control.markAsDirty();
      const children = (control as RfFormGroup | FormGroup | FormArray).controls;
      for (const child of Object.values(children)) {
        this.markAllAsDirty(child);
      }
    } else {
      (control as RfFormControl).markAllAsDirty();
    }
  }

  /**
   * Updates the `displayErrorsMode` for all controls that support it.
   *
   * @param errorMode - The error display mode to apply.
   */
  public changeDisplayErrorsMode(errorMode: RfErrorDisplayModes): void {
    this.displayErrorsMode = errorMode;
    this.changeDisplayErrorsModeInternal(this.controls, errorMode);
  }

  /**
   * Internal recursive helper that applies a given `displayErrorsMode`
   * to all `RfFormControl` children and their nested forms.
   *
   * @param controls - The controls to process.
   * @param errorMode - The error display mode to apply.
   */
  private changeDisplayErrorsModeInternal(
    controls: { [key: string]: AbstractControl },
    errorMode: RfErrorDisplayModes
  ): void {
    for (const control of Object.values(controls ?? {})) {
      if (
        control instanceof RfFormControl &&
        'rfComponent' in control &&
        control.rfComponent &&
        typeof control.rfComponent === 'object'
      ) {
        const components = Array.isArray(control.rfComponent) ? control.rfComponent : [control.rfComponent];
        for (const component of components) {
          component.displayErrorsMode.set(errorMode);
        }
        if ((control.rfComponent as any).form) {
          this.changeDisplayErrorsModeInternal((control.rfComponent as any).form.controls, errorMode);
        }
      }
    }
  }

  /**
   * Propagates the `submitted` state to all child controls and their components.
   */
  public changeSubmitedStatus(): void {
    this.propagateSubmitedStatus(this.controls);
  }

  /**
   * Internal recursive helper that propagates the current `submitted` state
   * to all `RfFormControl` children and their nested forms.
   *
   * @param controls - The controls to update.
   */
  private propagateSubmitedStatus(controls: { [key: string]: AbstractControl }): void {
    for (const control of Object.values(controls ?? {})) {
      if (
        control instanceof RfFormControl &&
        'rfComponent' in control &&
        control.rfComponent &&
        typeof control.rfComponent === 'object'
      ) {
        control.submitted = this._submitted;
        if ((control.rfComponent as any).form) {
          this.propagateSubmitedStatus((control.rfComponent as any).form.controls);
        }
      }
    }
  }

  /**
   * Enables or disables debug mode for all associated components inside the form.
   *
   * @param isEnabled - Whether to enable or disable debug mode.
   */
  public setDebug(isEnabled: boolean): void {
    for (const control of Object.values(this.controls ?? {})) {
      if (
        control instanceof RfFormControl &&
        'rfComponent' in control &&
        control.rfComponent &&
        typeof control.rfComponent === 'object'
      ) {
        const components = Array.isArray(control.rfComponent) ? control.rfComponent : [control.rfComponent];
        for (const component of components) {
          component.debug = isEnabled;
        }
      }
    }
  }

  /**
   * Marks controls as touched only if they currently hold a value.
   * Useful for triggering validation messages without marking untouched/empty fields.
   */
  public markControlsWithValueAsTouched(): void {
    for (const [, control] of Object.entries(this.controls)) {
      this.markControlIfHasValue(control);
      this.processNestedControls(control);
    }
  }

  /**
   * Focuses the first invalid form control for accessibility and error recovery.
   *
   * - Focus is always moved to the invalid control.
   * - Scrolling only occurs if the control is not visible within the viewport.
   * - Consumers may handle sticky header offsets via `scroll-margin-top`.
   *
   * Intended usage: call after a failed submit/validation.
   */
  public focusFirstInvalidField(): void {
    if (!this?.controls) {
      return;
    }

    const formControls = Object.keys(this.controls);

    for (const key of formControls) {
      const control = this.get(key) as RfFormControl;
      if (control && !control.valid && control.rfComponent) {
        const component = Array.isArray(control.rfComponent) ? control.rfComponent[0] : control.rfComponent;

        if (component) {
          component.focusError();
          requestAnimationFrame(() => {
            const element = component.getElementRef().nativeElement as HTMLElement;
            const rect = element.getBoundingClientRect();

            const SAFE_TOP = 16;
            const SAFE_BOTTOM = window.innerHeight - 16;

            const isAboveViewport = rect.top < SAFE_TOP;
            const isBelowViewport = rect.bottom > SAFE_BOTTOM;

            if (isAboveViewport || isBelowViewport) {
              element.scrollIntoView({ block: 'start', behavior: 'smooth' });
            }
          });
        }
        return;
      }
    }
  }

  /**
   * Marks a control as touched if it has a non-empty value.
   */
  private markControlIfHasValue(control: AbstractControl): void {
    const hasValue = this.hasNonEmptyValue(control.value);
    if (hasValue) {
      control.markAsTouched({ onlySelf: true });
    }
  }

  /**
   * Processes nested FormGroup, RfFormGroup, or FormArray controls recursively.
   */
  private processNestedControls(control: AbstractControl): void {
    if (control instanceof FormGroup || control instanceof RfFormGroup) {
      (control as RfFormGroup).markControlsWithValueAsTouched();
    } else if (control instanceof FormArray) {
      this.processFormArrayControls(control);
    }
  }

  /**
   * Processes all controls within a FormArray.
   */
  private processFormArrayControls(formArray: FormArray): void {
    for (const c of formArray.controls) {
      if (c instanceof FormGroup || c instanceof RfFormGroup) {
        (c as RfFormGroup).markControlsWithValueAsTouched();
      } else if (this.hasNonEmptyValue(c.value)) {
        c.markAsTouched({ onlySelf: true });
      }
    }
  }

  /**
   * Checks if a value is non-empty (not null, undefined, or empty string).
   */
  private hasNonEmptyValue(value: unknown): boolean {
    return value !== null && value !== undefined && value !== '';
  }

  /**
   * Clears a previously registered form name to allow reuse.
   *
   * @param formName - The name to remove from the registry.
   */
  public static clearFormName(formName: string): void {
    RfFormGroup.registeredFormNames.delete(formName);
  }

  /**
   * Clears all registered form names. Useful for tests or form resets.
   */
  public static resetNames(): void {
    RfFormGroup.registeredFormNames.clear();
  }
}

