@if (control() && debug() && !hide()) {
    <div class="card shadow-sm mt-3">
        <div class="card-header bg-dark text-white d-flex justify-content-between align-items-center">
            <span>Control status</span>
            <button
                class="btn btn-link p-0 m-0 text-white text-decoration-none"
                [attr.aria-label]="collapsed() ? 'Expand' : 'Collapse'"
                [title]="collapsed() ? 'Expand' : 'Collapse'"
                (click)="toggleCollapsed()">
                {{ collapsed() ? '➕' : '➖' }}
            </button>
        </div>
        @if (!collapsed()) {
            <div class="card-body p-3">
                <div class="row gy-2">
                    <div class="col-3">
                        <div class="fw-bold">Value</div>
                        <div>
                            <code class="small text-primary">{{ control()?.value | json }}</code>
                        </div>
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Touched</div>
                        <div
                            [class.text-success]="control()?.touched"
                            [class.text-muted]="!control()?.touched">
                            {{ control()?.touched }}
                        </div>
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Dirty</div>
                        <div
                            [class.text-success]="control()?.dirty"
                            [class.text-muted]="!control()?.dirty">
                            {{ control()?.dirty }}
                        </div>
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Invalid</div>
                        <div
                            [class.text-success]="control()?.valid"
                            [class.text-danger]="control()?.invalid">
                            {{ control()?.invalid }}
                        </div>
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Errors</div>
                        @if (errorsList.length > 0) {
                            @for (error of errorsList; track error.key) {
                                <div class="small ps-2">
                                    <strong>▪️{{ error.key }}</strong
                                    >: {{ error.value | json }}
                                </div>
                            }
                        } @else {
                            <span class="text-muted small">No errors</span>
                        }
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Errors display mode</div>
                        <div>
                            {{ displayErrorsMode() }}
                        </div>
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Validators</div>
                        @if (validatorsList.length > 0) {
                            @for (validator of validatorsList; track validator) {
                                <div class="small ps-2">
                                    <strong>▪️{{ validator }}</strong>
                                </div>
                            }
                        } @else {
                            <span class="text-muted small">No validators</span>
                        }
                    </div>
                    <div class="col-3">
                        <div class="fw-bold">Status</div>
                        <span
                            class="badge"
                            [ngClass]="{
                                'bg-success': control()?.status === 'VALID',
                                'bg-danger': control()?.status === 'INVALID',
                                'bg-info text-dark': control()?.status === 'PENDING',
                                'bg-light text-dark': control()?.status === 'DISABLED',
                            }">
                            {{ control()?.status }}
                        </span>
                    </div>
                </div>
            </div>
        }
    </div>
}

