    ::ng-deep {
        .rf-select_value-container {
            top: var(--rf-field-control-pad-top);
        }
    }
}

@media #{$until-mobile} {
    :host ::ng-deep {
        .rf-select:last-of-type {
            /* stylelint-disable-next-line selector-max-compound-selectors */
            .rf-select_list {
                right: 0;
            }
        }
    }
